INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Pratiques RH avec IA', 'Formation sur l’utilisation de l’IA pour optimiser le recrutement, la gestion des talents et les pratiques RH.', 2, 200000.00, 'entreprise', '2026-08-15', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre l’impact de l’IA sur les pratiques RH\n• Identifier les outils IA pour le recrutement et la gestion des talents\n• Développer des stratégies concrètes pour intégrer l’IA dans les RH\n• Améliorer la prise de décision et la performance commerciale grâce aux données RH\n• Optimiser les processus administratifs et renforcer la satisfaction des employés\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre l’impact de l’IA sur les pratiques RH et commerciales, identifier les outils IA applicables, développer des stratégies concrètes pour intégrer l’IA dans les RH et améliorer la performance organisationnelle.\n\n--- PRÉREQUIS ---\nConnaissances de base en gestion RH ou commerciale. Une familiarité avec les outils numériques est recommandée.\n\n--- CONTENU ---\nModule 1 : Introduction à l’IA appliquée aux RH\nModule 2 : L’IA au service du recrutement et de la gestion des talents\nModule 3 : Optimisation des pratiques RH grâce à l’IA\nModule 4 : L’IA pour renforcer la fonction commerciale\nModule 5 : Éthique, sécurité et adoption de l’IA en entreprise\nModule 6 : Atelier final – Plan d’action personnalisé\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nResponsables RH, chargés de recrutement, managers commerciaux, consultants en RH, entrepreneurs.\n\n--- MÉTHODES ---\nPrésentations interactives, études de cas, démonstrations d’outils IA, ateliers pratiques, Q&A et quiz interactifs.\n\n--- SUPPORTS ---\nSlides interactives, vidéos de démonstration, outils IA RH et CRM, chatbots, outils de scoring, fiches pratiques et guides pas-à-pas.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
